const html = $input.first().json.data || '';

function cleanHtmlToText(html) {
  if (!html || typeof html !== 'string') return '';
  if (html.includes('Attention Required! | Cloudflare')) return '';
  let cleaned = html.replace(/<(script|style|noscript|svg|canvas|iframe|video|audio|picture|source)[^>]*>[\s\S]*?<\/\1>/gi, '');
  cleaned = cleaned.replace(/<(script|style|noscript|svg|canvas|iframe|video|audio|picture|source)[^>]*\/>/gi, '');
  const parts = [];
  const tagPattern = /<(p|li|h[1-6])[^>]*>([\s\S]*?)<\/\1>/gi;
  let match;
  while ((match = tagPattern.exec(cleaned)) !== null) {
    let text = match[2];
    text = text.replace(/<br[^>]*>/gi, '\n');
    text = text.replace(/<[^>]+>/g, '');
    text = text.replace(/\u00a0/g, ' ');
    text = text.replace(/[ \t]+/g, ' ');
    text = text.replace(/\n{2,}/g, '\n');
    text = text.trim();
    if (text) parts.push(text);
  }
  return parts.join('\n');
}

// Extract impressum link from raw HTML
let impressumPath = null;
const linkPattern = /<a[^>]+href=["']([^"']+)['"][^>]*>[^<]*(?:impressum|imprint)[^<]*<\/a>/gi;
const linkMatch = linkPattern.exec(html);
if (linkMatch) impressumPath = linkMatch[1];

return [{ json: { homepageText: cleanHtmlToText(html), impressumPath } }];

const website = $('Execute Workflow Trigger').first().json.website || '';
const homepageText = $input.first().json.homepageText || '';
const impressumPath = $input.first().json.impressumPath || null;
let baseUrl = website.trim();
if (!baseUrl.startsWith('http')) baseUrl = 'https://' + baseUrl;
baseUrl = baseUrl.replace(/\/$/, '');
let impressumUrl;
if (impressumPath) {
  impressumUrl = impressumPath.startsWith('http') ? impressumPath : baseUrl + (impressumPath.startsWith('/') ? '' : '/') + impressumPath;
} else {
  impressumUrl = baseUrl + '/impressum';
}
return [{ json: { impressumUrl, homepageText } }];

