try {
  const resp = $input.first().json;
  // Validate OpenAI response structure
  if (!resp.choices || !resp.choices[0]?.message?.content) {
    return [{ json: { success: false } }];
  }
  const content = resp.choices[0].message.content;
  const parsed = JSON.parse(content);

  // If no useful data extracted (e.g. Cloudflare block → empty text → empty response)
  if (!parsed.website_summary && !parsed.email && !parsed.phone && (!parsed.geschaeftsfuehrer || parsed.geschaeftsfuehrer.length === 0)) {
    return [{ json: { success: false } }];
  }

  // Validate email format
  let email = parsed.email || null;
  if (email) {
    email = email.trim();
    if (!/^[^\s@]+@[^\s@]+\.[a-zA-Z]{2,}$/.test(email)) email = null;
  }

  // Normalize phone to +49 E.164
  let phone = parsed.phone || null;
  if (phone) {
    phone = phone.replace(/[^\d+]/g, '');
    if (phone.startsWith('+490')) phone = '+49' + phone.substring(4);
    if (phone.startsWith('0') && !phone.startsWith('00')) phone = '+49' + phone.substring(1);
    if (!phone.startsWith('+49')) phone = null;
  }

  return [{
    json: {
      success: true,
      website_summary: parsed.website_summary || '',
      im_contact_name: (parsed.geschaeftsfuehrer || []).map(g => typeof g === 'string' ? g : g.name).join(', '),
      im_email: email,
      im_tel: phone
    }
  }];
} catch (e) {
  return [{ json: { success: false } }];
}

